import{_ as l,o as a,c as n,j as e}from"./chunks/framework.DwgkYvd1.js";const i=JSON.parse('{"title":"日出以前","description":"","frontmatter":{"title":"日出以前","date":"2022-09-15T22:56:02.000Z","tags":null},"headers":[],"relativePath":"诗与散文/日出以前.md","filePath":"诗与散文/日出以前.md"}'),r={name:"诗与散文/日出以前.md"};function s(o,t,p,_,c,d){return a(),n("div",null,[...t[0]||(t[0]=[e("p",null,"天不亮便醒，发现窗里透出的深蓝。",-1),e("p",null,"​ 你知道这是天空的颜色，你也见过无数的天空，但唯独没有见过这般纯粹的蓝。他很安静，只是充当万象的底色，却衬起整个世界的祥和。",-1),e("p",null,"​ 于是你走近它，扶着窗，向外望去。这时，那般的纯粹又从天空中发散出来，降临在万物身上。你看见街灯，朦胧的光影勾勒出道路的轮廓。于是，道路上点点积水的晶莹便描画出了充满细雨的空气。偶有淡黄的车灯慢慢驶过，细雨便跳跃着在光下起舞。",-1),e("p",null,"​ 后来，几只伞出现在你的窗户中，那是早行的路人，在沉浸的凉意中赶路，各色的伞上依旧有水滴欢快的影子。你打开窗，冷而温柔的清晨的气息瞬间充满整个房间，像一滴蓝色的墨水落入水中。而那冷雨也变得真切，淅淅沥沥，落在街道上，落在房檐上，落在过往行人的伞上，落在无眠之人的心头，拍打着这座沉睡的城市。",-1),e("p",null,"​ 天边那蓝似乎褪了一些，对面的窗灯亮了。似乎在同一时间，空气喧嚣了起来。于是，你听到的，这座城市醒来了。在这喧嚣之外，就连雨声都不得不收敛一些，变为这繁忙清晨的背景音。",-1),e("p",null,"​ 就这样，在雨声中，在汽车的鸣笛和呼啸声中，在早行路人朴素的谈话之中，这个清冽的晚秋的清晨，开始了。",-1)])])}const m=l(r,[["render",s]]);export{i as __pageData,m as default};
